class User:
    def __init__(self, username: str, password: str):
        self.username = username
        self.password_hash = self._hash_password(password)
    
    def _hash_password(self, password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()
    
    def verify_password(self, password: str) -> bool:
        return self.password_hash == self._hash_password(password)


class Token:
    def __init__(self, token: str, username: str, expires_at: datetime):
        self.token = token
        self.username = username
        self.expires_at = expires_at
    
    def is_valid(self) -> bool:
        return datetime.now() < self.expires_at


class AuthSystem:
    def __init__(self, token_expiry_hours: int = 24):
        self.users: Dict[str, User] = {}
        self.tokens: Dict[str, Token] = {}
        self.token_expiry_hours = token_expiry_hours
    
    def register_user(self, username: str, password: str) -> bool:
        if username in self.users:
            return False
        self.users[username] = User(username, password)
        return True
    
    def login(self, username: str, password: str) -> Optional[str]:
        user = self.users.get(username)
        if not user or not user.verify_password(password):
            return None
        
        token_string = secrets.token_urlsafe(32)
        expires_at = datetime.now() + timedelta(hours=self.token_expiry_hours)
        token = Token(token_string, username, expires_at)
        self.tokens[token_string] = token
        
        return token_string
    
    def verify_token(self, token_string: str) -> Optional[str]:
        token = self.tokens.get(token_string)
        if not token or not token.is_valid():
            if token:
                del self.tokens[token_string]
            return None
        return token.username
    
    def logout(self, token_string: str) -> bool:
        if token_string in self.tokens:
            del self.tokens[token_string]
            return True
        return False
    
    def cleanup_expired_tokens(self):
        expired = [t for t, token in self.tokens.items() if not token.is_valid()]
        for token_string in expired:
            del self.tokens[token_string]


